<?php
// winter_badge_onefile_white.php
// ✅ "한 파일" + 로고가 **진짜 흰색 PNG**로 내장됨 (CSS invert 안 씀 = 브라우저 이슈 없음)
// - 가운데 중심점 기준 3D 회전(뱃지처럼) rotateY 기본
// - 거울글씨 방지(양면)
// - 배경 transparent 가능: ?bg=transparent
//
// 파라미터
//  axis=y|x   (기본 y)
//  dur=2.2    (초)
//  size=260   (px)
//  bg=111 / bg=transparent
//  outline=1  (기본 1) : 흰색이 밝은 배경에서도 보이도록 외곽 그림자
//  shadow=1   (기본 1) : 아래쪽 그림자

$axis = strtolower($_GET['axis'] ?? 'y');
if ($axis !== 'x' && $axis !== 'y') $axis = 'y';

$dur  = preg_match('/^\d+(\.\d+)?$/', $_GET['dur']  ?? '') ? ($_GET['dur']) : '2.2';
$size = preg_match('/^\d+$/',        $_GET['size'] ?? '') ? intval($_GET['size']) : 260;

$bg = $_GET['bg'] ?? '111';
if ($bg === 'transparent') $bg_css = 'transparent';
else {
  $bg = preg_replace('/[^0-9a-fA-F]/', '', $bg);
  $bg_css = (strlen($bg) === 3 || strlen($bg) === 6) ? ('#'.$bg) : '#111';
}

$outline = ($_GET['outline'] ?? '1') !== '0';
$shadow  = ($_GET['shadow']  ?? '1') !== '0';

// base64 PNG (투명 배경 + **흰색 로고**) 내장
$pngB64 = '';
?>
<!doctype html>
<html lang="ko">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width,initial-scale=1" />
  <title>Winter Badge 3D Spin (One File / White)</title>
  <style>
    body{
      margin:0;
      height:100vh;
      display:grid;
      place-items:center;
      background: <?= $bg_css ?>;
    }
    .stage{
      width: <?= $size ?>px;
      height: <?= $size ?>px;
      perspective: 900px;
      display:grid;
      place-items:center;
    }
    .badge{
      width:100%;
      height:100%;
      position:relative;
      transform-style: preserve-3d;
      transform-origin: 50% 50%;
      animation: spin <?= htmlspecialchars($dur, ENT_QUOTES, 'UTF-8') ?>s linear infinite;
      will-change: transform;
      <?php if ($outline && $shadow): ?>
      filter: drop-shadow(0 0 2px rgba(0,0,0,0.85)) drop-shadow(0 10px 25px rgba(0,0,0,0.35));
      <?php elseif ($outline): ?>
      filter: drop-shadow(0 0 2px rgba(0,0,0,0.85));
      <?php elseif ($shadow): ?>
      filter: drop-shadow(0 10px 25px rgba(0,0,0,0.35));
      <?php endif; ?>
    }
    .face{
      position:absolute;
      inset:0;
      backface-visibility: hidden;
      display:block;
    }
    .back{ transform: rotateY(180deg); }
    <?php if ($axis === 'x'): ?>
    .back{ transform: rotateX(180deg); }
    <?php endif; ?>

    @keyframes spin{
      from{ transform: rotate<?= strtoupper($axis) ?>(0deg); }
      to  { transform: rotate<?= strtoupper($axis) ?>(360deg); }
    }
  </style>
</head>
<body>
  <div class="stage">
    <div class="badge">
      <div class="face front">
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 600 600" width="100%" height="100%">
          <image href="data:image/png;base64,<?= $pngB64 ?>" x="0" y="0" width="600" height="600" />
        </svg>
      </div>
      <div class="face back">
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 600 600" width="100%" height="100%">
          <image href="data:image/png;base64,<?= $pngB64 ?>" x="0" y="0" width="600" height="600" />
        </svg>
      </div>
    </div>
  </div>
</body>
</html>
